const input = $input.first().json.content.parts[0].text;

function extractJson(data) {
  // Если уже объект с нужными полями
  if (typeof data === 'object' && data !== null && !Array.isArray(data)) {
    // Прямой объект с company
    if (data.company) return data;

    // Объект вида { "key": { company: ... } }
    for (const key of Object.keys(data)) {
      if (typeof data[key] === 'object' && data[key]?.company) {
        return data[key];
      }
      // Вложенная строка
      if (typeof data[key] === 'string') {
        try {
          const parsed = JSON.parse(data[key]);
          if (parsed?.company) return parsed;
        } catch {}
      }
    }
  }

  // Если строка
  if (typeof data === 'string') {
    // Убираем markdown ```json ... ```
    const cleaned = data
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/g, '')
      .trim();
    try {
      const parsed = JSON.parse(cleaned);
      if (parsed?.company) return parsed;
    } catch {}
  }

  return null;
}

const result = extractJson(input);

if (!result) {
  throw new Error('Failed to parse company JSON: ' + JSON.stringify(input));
}

return [{ json: {generatedCompanySummary: result} }];

